import request from '@/utils/request'

//获取首页轮播图
export function getcCarousel() {
    return request({
      url: process.env.VUE_APP_BASE_API+'/geekplus/getCarousel',
      method: 'get',
    })
}

//获取疫情数据
export function getcovid() {
    return request({
      url: '/covid/getAllData',
      method: 'get',
    })
}

//获取世界疫情数据
export function getWorldCovid() {
    return request({
      url: '/covid/getCovid19Foreign',
      method: 'get',
    })
}

//获取世界疫情数据
export function get163coviddata() {
  return request({
    url: '/163coviddata',
    method: 'get',
  })
}
